import{_ as a,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Primer Inicio: Dominar el Directorio de Datos | Antigravity Tools","description":"Aprende la ubicación del directorio de datos de Antigravity Tools y la gestión de registros. Domina cómo abrir el directorio de datos desde Configuración, limpiar registros, ejecutar en la bandeja y habilitar el autoinicio al encender, distinguiendo los dos tipos de inicio automático.","frontmatter":{"title":"Primer Inicio: Dominar el Directorio de Datos | Antigravity Tools","sidebarTitle":"Encontrar el Directorio de Datos","subtitle":"Lo esencial del primer inicio: directorio de datos, registros, bandeja y autoinicio","description":"Aprende la ubicación del directorio de datos de Antigravity Tools y la gestión de registros. Domina cómo abrir el directorio de datos desde Configuración, limpiar registros, ejecutar en la bandeja y habilitar el autoinicio al encender, distinguiendo los dos tipos de inicio automático.","tags":["primer inicio","directorio de datos","registros","bandeja","autoinicio"],"prerequisite":["start-getting-started","start-installation"],"order":3},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/start/first-run-data/index.md","filePath":"es/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"}'),o={name:"es/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"};function s(n,e,d,c,l,u){return r(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="lo-esencial-del-primer-inicio-directorio-de-datos-registros-bandeja-y-autoinicio" tabindex="-1">Lo esencial del primer inicio: Directorio de Datos, Registros, Bandeja y Autoinicio <a class="header-anchor" href="#lo-esencial-del-primer-inicio-directorio-de-datos-registros-bandeja-y-autoinicio" aria-label="Permalink to &quot;Lo esencial del primer inicio: Directorio de Datos, Registros, Bandeja y Autoinicio&quot;">​</a></h1><p>Muchas de las capacidades de Antigravity Tools que parecen &quot;mágicas&quot; (grupo de cuentas, cuotas, monitoreo, estadísticas, ejecución en segundo plano), al final se reducen a dos cosas: <strong>directorio de datos</strong> y <strong>registros</strong>. Si entiendes bien estos dos elementos desde el principio, ahorrarás mucho tiempo cuando necesites solucionar problemas más adelante.</p><h2 id="¿que-es-el-directorio-de-datos" tabindex="-1">¿Qué es el Directorio de Datos? <a class="header-anchor" href="#¿que-es-el-directorio-de-datos" aria-label="Permalink to &quot;¿Qué es el Directorio de Datos?&quot;">​</a></h2><p>El <strong>directorio de datos</strong> es la carpeta donde Antigravity Tools guarda su estado en tu máquina local: el JSON de cuentas, los archivos relacionados con cuotas, los archivos de registro y las bases de datos SQLite de Token Stats/Proxy Monitor se encuentran aquí. Cuando hagas copias de seguridad/migraciones/soluciones de problemas, solo necesitas ubicar este directorio para encontrar la fuente de datos autoritativa.</p><h2 id="lo-que-podras-hacer-despues-de-esta-leccion" tabindex="-1">Lo que podrás hacer después de esta lección <a class="header-anchor" href="#lo-que-podras-hacer-despues-de-esta-leccion" aria-label="Permalink to &quot;Lo que podrás hacer después de esta lección&quot;">​</a></h2><ul><li>Saber dónde está el directorio de datos de Antigravity Tools (y poder abrirlo con un clic)</li><li>Entender qué archivos vale la pena respaldar y cuáles son registros/caché</li><li>Solucionar problemas rápidamente localizando los registros y la base de datos de monitoreo</li><li>Entender la diferencia entre &quot;cerrar ventana&quot; y &quot;salir del programa&quot; (bandeja residente)</li><li>Distinguir dos tipos de autoinicio: al encender vs. inicio automático del proxy</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><ul><li>Quieres respaldar/migrar cuentas, pero no sabes dónde se guardan exactamente</li><li>La UI muestra errores o las llamadas al proxy fallan, pero no encuentras los registros</li><li>Cerraste la ventana pensando que el programa salió, pero sigue ejecutándose en segundo plano</li></ul><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><ul><li>Acabas de instalar Antigravity Tools y quieres confirmar &quot;dónde se guardan los datos&quot;</li><li>Te estás preparando para cambiar de computadora/reinstalar el sistema y quieres respaldar las cuentas y estadísticas primero</li><li>Necesitas solucionar problemas: fallos de OAuth, errores al refrescar cuotas, fallos al iniciar el proxy, respuestas 401/429</li></ul><h2 id="🎒-preparativos-antes-de-empezar" tabindex="-1">🎒 Preparativos antes de empezar <a class="header-anchor" href="#🎒-preparativos-antes-de-empezar" aria-label="Permalink to &quot;🎒 Preparativos antes de empezar&quot;">​</a></h2><ul><li>Antigravity Tools instalado y puedes abrirlo</li><li>Puedes acceder a la página Settings (entrada en la esquina superior derecha/barra lateral)</li><li>Tu cuenta de sistema tiene permisos para acceder a tu directorio Home</li></ul><div class="warning custom-block"><p class="custom-block-title">Aviso</p><p>Esta lección te dirá qué archivos son &quot;datos reales&quot;, pero no se recomienda editar manualmente estos archivos. Para cambiar configuraciones, modifica primero en la UI.</p></div><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p>Primero recuerda una frase:</p><p>&quot;<strong>El directorio de datos es la única fuente de verdad del estado local; los registros son el primer punto de entrada para solucionar problemas.</strong>&quot;</p><p>Antigravity Tools creará el directorio de datos <code>.antigravity_tools</code> en tu directorio Home y colocará allí las cuentas, registros, bibliotecas de estadísticas, etc. (si el directorio no existe, se creará automáticamente).</p><p>Al mismo tiempo, habilita la bandeja por defecto: cuando cierras la ventana, el programa no sale inmediatamente, sino que se oculta en la bandeja y continúa ejecutándose en segundo plano.</p><h2 id="sigue-conmigo" tabindex="-1">Sigue conmigo <a class="header-anchor" href="#sigue-conmigo" aria-label="Permalink to &quot;Sigue conmigo&quot;">​</a></h2><h3 id="paso-1-abrir-el-directorio-de-datos-desde-configuracion" tabindex="-1">Paso 1: Abrir el directorio de datos desde Configuración <a class="header-anchor" href="#paso-1-abrir-el-directorio-de-datos-desde-configuracion" aria-label="Permalink to &quot;Paso 1: Abrir el directorio de datos desde Configuración&quot;">​</a></h3><p><strong>Por qué</strong> Primero ubica con precisión el directorio de datos. Ya sea para respaldo o solución de problemas, tendrás un &quot;punto de anclaje&quot;.</p><p>En Antigravity Tools, abre Settings y cambia a Advanced.</p><p>Verás una casilla de solo lectura &quot;Data Directory&quot; (muestra la ruta real) con un botón de abrir al lado.</p><p>Haz clic en el botón de abrir.</p><p><strong>Deberías ver</strong>: el administrador de archivos del sistema abre un directorio con una ruta similar a <code>~/.antigravity_tools/</code>.</p><h3 id="paso-2-confirmar-la-ruta-de-tu-directorio-de-datos-multiplataforma" tabindex="-1">Paso 2: Confirmar la ruta de tu directorio de datos (multiplataforma) <a class="header-anchor" href="#paso-2-confirmar-la-ruta-de-tu-directorio-de-datos-multiplataforma" aria-label="Permalink to &quot;Paso 2: Confirmar la ruta de tu directorio de datos (multiplataforma)&quot;">​</a></h3><p><strong>Por qué</strong> Cuando escribas scripts para respaldo o soluciones de problemas desde la línea de comandos más adelante, necesitas saber la ruta real de este directorio en tu sistema.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-zXykc" id="tab-VPFGVFp" checked><label data-title="macOS/Linux" for="tab-VPFGVFp">macOS/Linux</label><input type="radio" name="group-zXykc" id="tab-7hP9b_6"><label data-title="Windows" for="tab-7hP9b_6">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force $dataDir</span></span></code></pre></div></div></div><p><strong>Deberías ver</strong>: el directorio existe (si es la primera vez que abres la página de configuración, el directorio se creará automáticamente).</p><h3 id="paso-3-reconocer-los-archivos-clave-en-el-directorio-de-datos" tabindex="-1">Paso 3: Reconocer los &quot;archivos clave&quot; en el directorio de datos <a class="header-anchor" href="#paso-3-reconocer-los-archivos-clave-en-el-directorio-de-datos" aria-label="Permalink to &quot;Paso 3: Reconocer los &quot;archivos clave&quot; en el directorio de datos&quot;">​</a></h3><p><strong>Por qué</strong> No todos los archivos vale la pena respaldar. Primero distingue &quot;cuáles son datos de cuentas&quot; y &quot;cuáles son bibliotecas de estadísticas/registros&quot;.</p><p>Los siguientes nombres de archivo provienen del código fuente del proyecto y son fijos:</p><table tabindex="0"><thead><tr><th>Lo que verás</th><th>Propósito</th><th>Lo que te interesa</th></tr></thead><tbody><tr><td><code>accounts.json</code></td><td>Índice de cuentas (contiene lista de cuentas/cuenta actual)</td><td>Se recomienda respaldar junto al migrar cuentas</td></tr><tr><td><code>accounts/</code></td><td>Un archivo <code>*.json</code> por cada cuenta</td><td>Este es el cuerpo principal de datos de cuentas</td></tr><tr><td><code>logs/</code></td><td>Directorio de registros de la aplicación</td><td>Prioridad al solucionar problemas</td></tr><tr><td><code>token_stats.db</code></td><td>Base de datos SQLite de Token Stats</td><td>Los datos que ves en la página Token Stats provienen de aquí</td></tr><tr><td><code>proxy_logs.db</code></td><td>Base de datos SQLite de Proxy Monitor</td><td>Los registros de solicitudes que ves en la página Monitor provienen de aquí</td></tr><tr><td><code>warmup_history.json</code></td><td>Historial local de Smart Warmup</td><td>Principalmente usado para evitar warmup duplicados</td></tr><tr><td><code>update_settings.json</code></td><td>Configuración de verificación de actualizaciones (autoverificación/intervalo, etc.)</td><td>Generalmente no necesitas modificarlo manualmente</td></tr></tbody></table><p><strong>Deberías ver</strong>: al menos existe el directorio <code>logs/</code>; si aún no has agregado cuentas, <code>accounts.json</code>/<code>accounts/</code> pueden no aparecer.</p><h3 id="paso-4-memorizar-la-ubicacion-de-los-registros-necesario-para-solucionar-problemas" tabindex="-1">Paso 4: Memorizar la ubicación de los registros (necesario para solucionar problemas) <a class="header-anchor" href="#paso-4-memorizar-la-ubicacion-de-los-registros-necesario-para-solucionar-problemas" aria-label="Permalink to &quot;Paso 4: Memorizar la ubicación de los registros (necesario para solucionar problemas)&quot;">​</a></h3><p><strong>Por qué</strong> Los mensajes de error de la UI generalmente solo muestran &quot;el fenómeno&quot;, la causa real del fallo (por ejemplo, fallo de solicitud, fallo de lectura/escritura de archivo) a menudo está en los registros.</p><p>Antigravity Tools escribe los registros en <code>logs/</code> dentro del directorio de datos.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-mdR1n" id="tab-2uNTcpW" checked><label data-title="macOS/Linux" for="tab-2uNTcpW">macOS/Linux</label><input type="radio" name="group-mdR1n" id="tab-zfRCA_8"><label data-title="Windows" for="tab-zfRCA_8">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>Deberías ver</strong>: existen archivos de registro rotados por día en el directorio (los nombres de archivo comienzan con <code>app.log</code>).</p><h3 id="paso-5-cuando-necesites-limpiar-registros-usa-la-limpieza-con-un-clic-desde-configuracion" tabindex="-1">Paso 5: Cuando necesites &quot;limpiar registros&quot;, usa la limpieza con un clic desde Configuración <a class="header-anchor" href="#paso-5-cuando-necesites-limpiar-registros-usa-la-limpieza-con-un-clic-desde-configuracion" aria-label="Permalink to &quot;Paso 5: Cuando necesites &quot;limpiar registros&quot;, usa la limpieza con un clic desde Configuración&quot;">​</a></h3><p><strong>Por qué</strong> Algunos problemas solo quieres reproducir una vez y luego mantener solo el registro de esa ocasión; en ese caso es mejor limpiar los registros primero para facilitar la comparación.</p><p>En Settings -&gt; Advanced, encuentra el área de registros y haz clic en &quot;Clear Logs&quot;.</p><p><strong>Deberías ver</strong>: aparece un cuadro de confirmación; después de confirmar muestra limpieza exitosa.</p><div class="tip custom-block"><p class="custom-block-title">Dos cosas de las que te preocuparás</p><ul><li>Los registros realizan automáticamente &quot;rotación diaria&quot; y al iniciar intentan limpiar registros antiguos de más de 7 días.</li><li>&quot;Clear Logs&quot; truncará los archivos de registro a 0 bytes, lo que facilita que el proceso en ejecución continúe escribiendo en el mismo descriptor de archivo.</li></ul></div><h3 id="paso-6-entender-la-diferencia-entre-cerrar-ventana-y-salir-del-programa-bandeja" tabindex="-1">Paso 6: Entender la diferencia entre &quot;cerrar ventana&quot; y &quot;salir del programa&quot; (bandeja) <a class="header-anchor" href="#paso-6-entender-la-diferencia-entre-cerrar-ventana-y-salir-del-programa-bandeja" aria-label="Permalink to &quot;Paso 6: Entender la diferencia entre &quot;cerrar ventana&quot; y &quot;salir del programa&quot; (bandeja)&quot;">​</a></h3><p><strong>Por qué</strong> Antigravity Tools habilita la bandeja por defecto; cuando haces clic en cerrar en la esquina superior derecha de la ventana, el programa se ocultará en la bandeja y continuará ejecutándose. Si crees que salió, fácilmente aparecerá la ilusión de &quot;el puerto sigue ocupado/sigue ejecutándose en segundo plano&quot;.</p><p>Puedes confirmar con este pequeño flujo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Operación: cerrar ventana (no salir)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Paso 1                Paso 2                               │</span></span>
<span class="line"><span>│  Cerrar ventana    →   Buscar el icono en la bandeja/barra de menú del sistema  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Deberías ver: el icono de la bandeja todavía existe, haz clic para volver a mostrar la ventana.</span></span></code></pre></div><p>El menú de la bandeja también tiene dos acciones comunes (muy convenientes cuando no usas la UI):</p><ul><li>Cambiar cuenta: cambiar a la siguiente cuenta</li><li>Refrescar cuota: refrescar la cuota de la cuenta actual (al mismo tiempo notificará al frontend para actualizar la visualización)</li></ul><h3 id="paso-7-configurar-el-autoinicio-al-encender-para-que-se-inicie-minimizado-automaticamente" tabindex="-1">Paso 7: Configurar el autoinicio al encender (para que se inicie minimizado automáticamente) <a class="header-anchor" href="#paso-7-configurar-el-autoinicio-al-encender-para-que-se-inicie-minimizado-automaticamente" aria-label="Permalink to &quot;Paso 7: Configurar el autoinicio al encender (para que se inicie minimizado automáticamente)&quot;">​</a></h3><p><strong>Por qué</strong> Si esperas que funcione como un &quot;servicio residente&quot; (bandeja residente + refresco en segundo plano), el autoinicio al encender te ahorrará tener que abrirlo manualmente cada vez.</p><p>En Settings -&gt; General encuentra &quot;Auto-start on boot&quot;, selecciona habilitar.</p><p><strong>Deberías ver</strong>: muestra habilitado exitosamente después de cambiar; la próxima vez que inicies al encender se ejecutará con el parámetro <code>--minimized</code>.</p><div class="info custom-block"><p class="custom-block-title">Dos tipos de &quot;autoinicio&quot;, no los confundas</p><table tabindex="0"><thead><tr><th>Nombre</th><th>A qué se refiere</th><th>Evidencia</th></tr></thead><tbody><tr><td>Autoinicio al encender</td><td>Iniciar automáticamente Antigravity Tools después de que la computadora se inicia (la aplicación de escritorio en sí)</td><td>El parámetro de inicio incluye <code>--minimized</code>, y se proporciona el comando <code>toggle_auto_launch</code></td></tr><tr><td>Autoinicio del proxy</td><td>Después de que Antigravity Tools se inicia, si está configurado <code>proxy.auto_start=true</code>, intentará iniciar automáticamente el servicio local de proxy</td><td>Al iniciar la aplicación lee la configuración y ejecuta <code>start_proxy_service(...)</code></td></tr></tbody></table></div><h2 id="puntos-de-verificacion-✅" tabindex="-1">Puntos de verificación ✅ <a class="header-anchor" href="#puntos-de-verificacion-✅" aria-label="Permalink to &quot;Puntos de verificación ✅&quot;">​</a></h2><ul><li>[ ] Puedes ver la ruta real del directorio de datos en Settings -&gt; Advanced</li><li>[ ] Puedes abrir el directorio de datos y reconocer aproximadamente <code>accounts.json</code>, <code>accounts/</code>, <code>logs/</code>, <code>token_stats.db</code>, <code>proxy_logs.db</code></li><li>[ ] Sabes que los registros están en <code>logs/</code> y puedes verlos rápidamente desde la línea de comandos</li><li>[ ] Sabes que después de cerrar la ventana el programa todavía está en la bandeja, para salir usa Quit del menú de la bandeja</li><li>[ ] Puedes distinguir entre &quot;autoinicio al encender&quot; y &quot;autoinicio del proxy&quot;</li></ul><h2 id="recordatorios-de-trampas" tabindex="-1">Recordatorios de trampas <a class="header-anchor" href="#recordatorios-de-trampas" aria-label="Permalink to &quot;Recordatorios de trampas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Escenario</th><th>Lo que podrías hacer (❌)</th><th>Práctica recomendada (✓)</th></tr></thead><tbody><tr><td>No encuentras el directorio de datos</td><td>Buscar desordenadamente el directorio de instalación de la App en el sistema</td><td>Ve directamente a Settings -&gt; Advanced para ver &quot;Data Directory&quot; y abrir con un clic</td></tr><tr><td>Cerraste la ventana pensando que salió</td><td>Después de hacer clic en cerrar la ventana ir a cambiar configuración/cambiar puerto</td><td>Primero verifica si el icono de la bandeja todavía existe; para salir usa Quit de la bandeja</td></tr><tr><td>Demasiados registros difíciles de diagnosticar</td><td>Mientras reproduces el problema buscar en registros antiguos</td><td>Primero &quot;limpiar registros&quot;, luego reproducir una vez, finalmente solo ver el archivo de registro de esta vez</td></tr><tr><td>Quieres modificar datos de cuentas</td><td>Editar manualmente <code>accounts/*.json</code></td><td>Usa el flujo de importación/exportación/migración de la UI (la siguiente sección relacionada explicará)</td></tr></tbody></table><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><ul><li>El directorio de datos está fijo en <code>.antigravity_tools</code> bajo Home (en macOS/Linux generalmente aparece como directorio oculto), cuentas/registros/bibliotecas de estadísticas están aquí</li><li>El directorio de registros es <code>logs/</code>, prioridad al solucionar problemas; cuando sea necesario puedes limpiar con un clic desde la página de configuración</li><li>Cerrar la ventana ocultará en la bandeja y continuará ejecutándose; para salir completamente usa Quit de la bandeja</li><li>Hay dos tipos de autoinicio: autoinicio al encender (aplicación) y autoinicio del proxy (Proxy)</li></ul><hr><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../add-account/">Agregar cuenta: dos canales OAuth/Refresh Token y mejores prácticas</a></strong>.</p></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver ubicaciones del código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Ubicación del directorio de datos (<code>~/.antigravity_tools</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L33" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-33</td></tr><tr><td>Índice de cuentas y directorio de archivos de cuentas (<code>accounts.json</code> / <code>accounts/</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L46" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-46</td></tr><tr><td>Directorio de registros y rotación diaria (<code>logs/</code> + <code>app.log</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L17-L83" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>17-83</td></tr><tr><td>Limpiar registros (truncar archivo)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L149-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>149-169</td></tr><tr><td>Página de configuración muestra directorio de datos + abrir con un clic</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L525-L576" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>525-576</td></tr><tr><td>Página de configuración limpiar registros con un clic (botón + lógica de diálogo)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L127-L135" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>127-135</td></tr><tr><td>Página de configuración limpiar registros con un clic (botón de pestaña Advanced)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L732-L747" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>732-747</td></tr><tr><td>Menú de bandeja y eventos de clic (cambiar cuenta/refrescar/mostrar/salir)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/tray.rs#L9-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/tray.rs</code></a></td><td>9-158</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Interruptor de autoinicio al encender (<code>toggle_auto_launch</code> / <code>is_auto_launch_enabled</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/autostart.rs#L4-L39" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/autostart.rs</code></a></td><td>4-39</td></tr><tr><td>Comandos: abrir directorio de datos con un clic / obtener ruta / limpiar registros</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L578-L621" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>578-621</td></tr><tr><td>Nombre de archivo de base de datos Token Stats (<code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L61" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-61</td></tr><tr><td>Nombre de archivo de base de datos Proxy Monitor (<code>proxy_logs.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L5-L8" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>5-8</td></tr><tr><td>Nombre de archivo de historial Warmup (<code>warmup_history.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L14-L17" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>14-17</td></tr><tr><td>Nombre de archivo de configuración de actualizaciones (<code>update_settings.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/update_checker.rs#L150-L177" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/update_checker.rs</code></a></td><td>150-177</td></tr><tr><td>Autoinicio del proxy (iniciar servicio cuando <code>proxy.auto_start=true</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L107-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>107-126</td></tr></tbody></table></details><h2 id="proxima-leccion-1" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion-1" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../add-account/">Agregar cuenta: dos canales OAuth/Refresh Token y mejores prácticas</a></strong>.</p><p>Aprenderás:</p><ul><li>Cuándo usar OAuth y cuándo usar directamente refresh_token</li><li>Cómo manejar cuando falla el callback o no se puede obtener refresh_token</li><li>Cómo importar refresh_token en lote para construir rápidamente un grupo de cuentas</li></ul></blockquote>`,69)])])}const g=a(o,[["render",s]]);export{m as __pageData,g as default};
